                return; // qualified — not ambiguous
            const name = getColumnName(node);
            if (!name || name === '*' || selectAliases.has(name))
                return;
            const owners = fromTables.filter((t) => t.columns.some((c) => c.name === name));
            if (owners.length < 2 || seen.has(name))
                return;
            seen.add(name);
