// nested SELECTs (their own scope).
function containsFunction(node, fnLower) {
    if (!node || typeof node !== 'object')
        return false;
    if (node.type === 'select')
        return false;
    if (getFunctionName(node)?.toLowerCase() === fnLower)
        return true;
    for (const key of Object.keys(node)) {
        const v = node[key];
        if (Array.isArray(v)) {
            for (const item of v)
                if (containsFunction(item, fnLower))
                    return true;
        }
        else if (v && typeof v === 'object') {
            if (containsFunction(v, fnLower))
                return true;
        }
    }
    return false;
}
// ── COALESCE_IN_JOIN_KEY (no schema) ─────────────────────────────────────────
